INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '908d316a-a355-4ef4-9f8e-d339a65841ad',
  '00000000-0000-0000-0000-000000000001',
  $escape$Rails Input Validation — Schema Validation at the Boundary with Strong Parameters and ActiveModel$escape$,
  $escape$Rails splits validation into two layers: parameter filtering at the controller boundary and model-level schema validation. Strong Parameters (`require`/`permit`) prevent mass-assignment but don't validate shape or types — they silently drop unexpected keys. For tighter boundary validation, reach for `ActiveModel::Attributes` with type coercion on a plain Ruby object (no DB table needed), or use a form object backed by `ActiveModel::Validations`. This catches malformed input before it touches ActiveRecord, keeping your models clean.

For error responses, `render json: { errors: resource.errors.full_messages }, status: :unprocessable_entity` is idiomatic Rails. Pair it with `rescue_from ActionController::ParameterMissing` in `ApplicationController` to return a consistent 400 when a required root key is absent. Avoid leaking internal field names — use `errors.as_json` with `full_messages: true` or a custom serializer. For APIs, the `jsonapi-serializer` gem enforces a spec-compliant error envelope that clients can rely on.$escape$,
  $escape$# app/forms/create_user_form.rb
class CreateUserForm
  include ActiveModel::Model
  include ActiveModel::Attributes

  attribute :email,    :string
  attribute :age,      :integer
  attribute :role,     :string, default: "viewer"

  validates :email, presence: true, format: { with: URI::MailTo::EMAIL_REGEXP }
  validates :age,   numericality: { greater_than: 0, less_than: 130 }, allow_nil: true
  validates :role,  inclusion: { in: %w[viewer editor admin] }
end

# app/controllers/users_controller.rb
def create
  form = CreateUserForm.new(user_params)
  return render json: { errors: form.errors.full_messages }, status: :unprocessable_entity unless form.valid?

  user = User.create!(email: form.email, age: form.age, role: form.role)
  render json: UserSerializer.new(user), status: :created
end

private

def user_params
  params.require(:user).permit(:email, :age, :role)
end$escape$,
  $escape$ruby$escape$,
