INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'bc8d60d9-9342-4f43-afc0-47fe8a52586c',
  '00000000-0000-0000-0000-000000000001',
  $escape$Rails Configuration — Env Vars, Credentials, and Settings Classes Done Right$escape$,
  $escape$Rails gives you three distinct layers for configuration, and mixing them up causes headaches. Use ENV vars for infrastructure concerns (DATABASE_URL, REDIS_URL) that change per deployment. Use Rails credentials (`rails credentials:edit`) for secrets that must be encrypted at rest — API keys, Stripe secrets, JWT signing keys. Access them via `Rails.application.credentials.stripe[:secret_key]`. For structured app-level settings that aren't secrets, use `config/settings.yml` with a gem like `config` (aka Railsconfig), which gives you typed, environment-aware access through `Settings.feature_flags.new_onboarding`. Avoid scattering `ENV.fetch` calls across models and controllers — centralize them in a dedicated `AppConfig` class or an initializer that validates required vars at boot using `ENV.fetch('KEY') { raise 'KEY missing' }`. This turns a runtime crash mid-request into a loud startup failure. In Rails 7.1+, `config.x` namespace lets you attach arbitrary config to the app object (`config.x.max_upload_mb = 10`) without a gem, accessible as `Rails.application.config.x.max_upload_mb` anywhere.$escape$,
  $escape$# config/initializers/app_config.rb
module AppConfig
  STRIPE_SECRET  = ENV.fetch('STRIPE_SECRET_KEY')  { raise 'STRIPE_SECRET_KEY is not set' }
  REDIS_URL      = ENV.fetch('REDIS_URL', 'redis://localhost:6379/0')
end

# Access encrypted credentials (stored in config/credentials.yml.enc)
stripe_key = Rails.application.credentials.stripe[:secret_key]

# Rails 7.1+ config.x namespace (no gem needed)
# config/application.rb
config.x.uploads.max_size_mb = ENV.fetch('MAX_UPLOAD_MB', '10').to_i

# Anywhere in the app
Rails.application.config.x.uploads.max_size_mb  # => 10$escape$,
  $escape$ruby$escape$,
