INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '098b87c6-90e0-4f14-a195-a487ea857d1d',
  '00000000-0000-0000-0000-000000000001',
  $escape$Rails Background Jobs — Sidekiq, ActiveJob, and Worker Process Patterns$escape$,
  $escape$Rails background job processing centers on ActiveJob as the queue adapter abstraction, with Sidekiq as the de facto production backend. Define a job by inheriting from ApplicationJob, set queue_as to control priority lanes, and enqueue with perform_later. Sidekiq reads from Redis-backed queues using a thread pool — configure concurrency in sidekiq.yml alongside named queues and their weights.

For scheduled/recurring jobs, sidekiq-cron or the built-in Sidekiq Pro scheduler lets you define cron expressions in a YAML file loaded at boot. Avoid storing large objects in job arguments — pass an ActiveRecord ID and reload inside perform, since the object state may be stale by execution time.

Retry semantics are critical: Sidekiq retries 25 times with exponential backoff by default. Override sidekiq_options retries: 5 per job class, and implement the sidekiq_retries_exhausted block for dead-job handling. Use discard_on and retry_on at the ActiveJob layer for exception-specific routing. Run workers as separate Puma-adjacent processes — never in-process in production.$escape$,
  $escape$# app/jobs/send_welcome_email_job.rb
class SendWelcomeEmailJob < ApplicationJob
  queue_as :mailers
  sidekiq_options retries: 3

  discard_on ActiveRecord::RecordNotFound

  sidekiq_retries_exhausted do |msg, ex|
    Sentry.capture_exception(ex, extra: { job_args: msg['args'] })
  end

  def perform(user_id)
    user = User.find(user_id) # reload — never pass the object directly
    UserMailer.welcome(user).deliver_now
  end
end

# Enqueue from anywhere
SendWelcomeEmailJob.perform_later(user.id)
SendWelcomeEmailJob.set(wait: 5.minutes).perform_later(user.id)$escape$,
  $escape$ruby$escape$,
