INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '177cb0c3-db39-4b15-929e-c8c70e84440b',
  '00000000-0000-0000-0000-000000000001',
  $escape$Rails Monitoring — Health Checks, Prometheus Metrics, and OpenTelemetry Tracing$escape$,
  $escape$Rails 7.1 ships a built-in `/up` health endpoint via `get "up" => "rails/health#show"` — it returns 200 only when the app boots without error. Extend it by subclassing `Rails::HealthController` and adding custom checks against `ActiveRecord::Base.connection` or `Rails.cache`. For metrics, `prometheus_exporter` is the idiomatic choice: a collector process aggregates stats pushed from Puma workers via `ActiveSupport::Notifications`. Subscribe to `process_action.action_controller` and `sql.active_record` to expose per-endpoint latency and query count gauges without patching middleware. For distributed tracing, `opentelemetry-instrumentation-rails` auto-instruments the full request lifecycle — controllers, Active Record, Active Job, and Action Cable — by registering a Rack middleware and wrapping `ActiveSupport::Notifications`. Configure the OTLP exporter to push spans to Jaeger or Honeycomb. The three signals compose cleanly: health checks for liveness/readiness probes, Prometheus for RED metrics, and OTel traces for root-cause analysis. All three can be wired without monkey-patching core Rails internals.$escape$,
  $escape$# config/initializers/opentelemetry.rb
OpenTelemetry::SDK.configure do |c|
  c.service_name = "my-rails-app"
  c.use "OpenTelemetry::Instrumentation::Rails"
  c.use "OpenTelemetry::Instrumentation::ActiveRecord"
  c.use "OpenTelemetry::Instrumentation::ActiveJob"
end

# config/routes.rb
get "up" => "rails/health#show"   # liveness probe (Rails 7.1+)

# config/initializers/prometheus.rb
require "prometheus_exporter/instrumentation"
PrometheusExporter::Instrumentation::ActiveRecord.start(
  custom_labels: { app: "my-rails-app" },
  config_labels: [:database, :host]
)$escape$,
  $escape$ruby$escape$,
