INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '74541e3d-b9bd-4dcb-849b-e17627d82c2d',
  '00000000-0000-0000-0000-000000000001',
  $escape$Rails Hotwire — Phoenix LiveView-Style Reactivity Without a JS Framework$escape$,
  $escape$Rails ships Hotwire by default — Turbo + Stimulus — giving you Phoenix LiveView-style server-driven UI without React or a separate API layer. Turbo Streams let you push partial HTML updates over ActionCable directly from your models. Declare `broadcasts_to` on an ActiveRecord model and Rails auto-publishes a Turbo Stream on create/update/destroy. On the client, `turbo_stream_from` subscribes and surgically patches the DOM — no full-page reload, no client state management. The broadcast targets a DOM id convention Rails enforces via `dom_id(@post)`, so the server and view stay in sync by convention. Unlike Phoenix LiveView, which diffs a stateful server process, Turbo Streams are stateless partial renders — simpler operationally, no persistent socket process per user. For optimistic UI or finer control, `Turbo::StreamsChannel.broadcast_replace_to` lets you push from anywhere: jobs, service objects, webhooks. Combined with `ActionCable`'s Redis adapter, this scales horizontally with zero front-end build tooling changes. It's the most Rails-idiomatic path to real-time — convention over WebSocket configuration.$escape$,
  $escape$# app/models/post.rb
class Post < ApplicationRecord
  broadcasts_to ->(post) { :posts }
end

# app/views/posts/index.html.erb
<%= turbo_stream_from :posts %>
<div id="posts">
  <%= render @posts %>
</div>

# app/views/posts/_post.html.erb
<div id="<%= dom_id(post) %>">
  <h2><%= post.title %></h2>
</div>

# From a background job — push anywhere:
Turbo::StreamsChannel.broadcast_replace_to(
  :posts,
  target: dom_id(post),
  partial: "posts/post",
  locals: { post: post }
)$escape$,
  $escape$ruby$escape$,
